import { useState, type FormEvent } from 'react';
import { Check } from 'lucide-react';

// 表单全部英文，避免多余汉字
export default function ContactForm() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [subject, setSubject] = useState('');
  const [message, setMessage] = useState('');
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [sent, setSent] = useState(false);

  const validate = () => {
    const e: Record<string, string> = {};
    if (!name.trim()) e.name = 'Please enter your name';
    if (!email.trim()) e.email = 'Please enter your email';
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim())) e.email = 'Invalid email format';
    if (!subject.trim()) e.subject = 'Please enter a subject';
    if (!message.trim()) e.message = 'Please write a message';
    return e;
  };

  const onSubmit = (ev: FormEvent) => {
    ev.preventDefault();
    const e = validate();
    setErrors(e);
    if (Object.keys(e).length) return;
    setSent(true);
    setName(''); setEmail(''); setSubject(''); setMessage('');
    setTimeout(() => setSent(false), 2500);
  };

  return (
    <section className="max-w-2xl mx-auto mt-20">
      <div className="uppercase tracking-[0.3em] text-xs text-ink-500 text-center">
        Send a Message
      </div>
      <h3 className="font-display text-4xl text-center mt-3">Say Hello</h3>

      {sent && (
        <div className="mt-8 mx-auto inline-flex items-center gap-2 px-5 py-3 bg-black text-white text-sm animate-fade-in" style={{ display: 'block', textAlign: 'center' }}>
          <span className="inline-flex items-center gap-2">
            <Check className="w-4 h-4" />
            Thanks — we&rsquo;ll reply soon.
          </span>
        </div>
      )}

      <form onSubmit={onSubmit} className="mt-12 space-y-6" noValidate>
        <div>
          <input className="input-underline" placeholder="Name" value={name} onChange={(e) => setName(e.target.value)} />
          {errors.name && <p className="text-xs text-red-600 mt-2">{errors.name}</p>}
        </div>
        <div>
          <input className="input-underline" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} />
          {errors.email && <p className="text-xs text-red-600 mt-2">{errors.email}</p>}
        </div>
        <div>
          <input className="input-underline" placeholder="Subject" value={subject} onChange={(e) => setSubject(e.target.value)} />
          {errors.subject && <p className="text-xs text-red-600 mt-2">{errors.subject}</p>}
        </div>
        <div>
          <textarea className="input-underline resize-none" rows={5} placeholder="Your message…" value={message} onChange={(e) => setMessage(e.target.value)} />
          {errors.message && <p className="text-xs text-red-600 mt-2">{errors.message}</p>}
        </div>

        <div className="text-center mt-10">
          <button type="submit" className="btn-primary w-full md:w-auto px-12">
            Send
          </button>
        </div>
      </form>
    </section>
  );
}
