import { Link, NavLink } from 'react-router-dom';
import { useState } from 'react';
import { Menu, X } from 'lucide-react';
import { cn } from '@/lib/utils';

// 6 个导航项（全英文，与 HOME/IMAGES/VIDEOS 并排）
const NAV = [
  { to: '/', label: 'Home' },
  { to: '/images', label: 'Images' },
  { to: '/videos', label: 'Videos' },
  { to: '/about', label: 'About' },
  { to: '/audio', label: 'Audio' },
  { to: '/contact', label: 'Contact' },
];

export default function Navbar() {
  const [open, setOpen] = useState(false);

  return (
    <header className="sticky top-0 z-50 bg-white/85 backdrop-blur-md border-b hairline">
      <nav className="container max-w-site h-16 md:h-20 flex items-center justify-between">
        <Link
          to="/"
          className="flex items-center gap-3"
          onClick={() => setOpen(false)}
        >
          {/* Logo：SY 字母替代汉字 */}
          <span className="w-8 h-8 border border-black flex items-center justify-center font-display text-sm tracking-tight">
            SY
          </span>
          <span className="font-display text-xl tracking-[0.25em] hidden sm:block uppercase">
            Song Yan
          </span>
        </Link>

        <ul className="hidden md:flex items-center gap-10">
          {NAV.map((n) => (
            <li key={n.to}>
              <NavLink
                to={n.to}
                end={n.to === '/'}
                className={({ isActive }) =>
                  cn(
                    'text-sm uppercase tracking-[0.2em] transition-colors relative py-2',
                    isActive ? 'text-black' : 'text-ink-600 hover:text-black',
                  )
                }
              >
                {({ isActive }) => (
                  <span className="relative">
                    {n.label}
                    <span
                      className={cn(
                        'absolute left-0 -bottom-1 h-px bg-black transition-all duration-300',
                        isActive ? 'w-full' : 'w-0 group-hover:w-full',
                      )}
                    />
                  </span>
                )}
              </NavLink>
            </li>
          ))}
        </ul>

        <button
          onClick={() => setOpen((v) => !v)}
          className="md:hidden p-2 text-ink-700"
          aria-label="Menu"
        >
          {open ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </nav>

      {open && (
        <div className="md:hidden border-t hairline bg-white animate-fade-in">
          <ul className="container max-w-site py-4 space-y-1">
            {NAV.map((n) => (
              <li key={n.to}>
                <NavLink
                  to={n.to}
                  end={n.to === '/'}
                  onClick={() => setOpen(false)}
                  className={({ isActive }) =>
                    cn(
                      'block py-3 px-2 border-b hairline last:border-0',
                      isActive ? 'text-black font-semibold' : 'text-ink-600',
                    )
                  }
                >
                  <span className="font-display text-lg uppercase tracking-[0.15em]">{n.label}</span>
                </NavLink>
              </li>
            ))}
          </ul>
        </div>
      )}
    </header>
  );
}
