import { Mail, Phone, MapPin, Clock } from 'lucide-react';

// 所有卡片标题和内容：全英文，避免多余汉字
const cards = [
  {
    icon: Mail,
    title: 'Email',
    lines: ['987832173@qq.com'],
  },
  {
    icon: Phone,
    title: 'Phone',
    lines: ['15585589252'],
  },
  {
    icon: MapPin,
    title: 'Studio',
    lines: ['Chaoyang, Beijing', 'No. 88 Studio Lane'],
  },
  {
    icon: Clock,
    title: 'Hours',
    lines: ['Mon - Fri', '10:00 - 18:00'],
  },
];

export default function ContactCards() {
  return (
    <div className="md:grid md:grid-cols-2 xl:grid-cols-4 gap-6 mt-12">
      {cards.map((c) => (
        <div
          key={c.title}
          className="bg-white border hairline p-8 hover:-translate-y-1 hover:shadow-paper transition-all duration-500"
        >
          <div className="w-12 h-12 rounded-full border hairline flex items-center justify-center mb-5 text-ink-800">
            <c.icon className="w-5 h-5" strokeWidth={1.8} />
          </div>
          <div className="font-display text-2xl mb-2">{c.title}</div>
          <div className="text-ink-600 leading-relaxed">
            {c.lines.map((l, i) => (
              <div key={i}>{l}</div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}
