import TrackItem from './TrackItem';
import { useAudioStore } from '@/store/useAudioStore';

export default function Playlist() {
  const tracks = useAudioStore((s) => s.tracks);
  const currentTrackId = useAudioStore((s) => s.currentTrackId);
  const isPlaying = useAudioStore((s) => s.isPlaying);
  const playTrack = useAudioStore((s) => s.playTrack);
  const toggleLike = useAudioStore((s) => s.toggleLike);
  const likedIds = useAudioStore((s) => s.likedIds);

  return (
    <div>
      <div className="flex items-end justify-between">
        <div className="uppercase tracking-[0.3em] text-xs text-ink-500">Playlist</div>
        <div className="text-sm text-ink-500 tabular-nums">
          {tracks.length} tracks
        </div>
      </div>

      <div className="mt-4 overflow-hidden rounded-t-[2px] border hairline">
        {tracks.map((t, i) => (
          <TrackItem
            key={t.id}
            track={t}
            index={i}
            isActive={currentTrackId === t.id}
            isPlaying={isPlaying && currentTrackId === t.id}
            onPlay={() => playTrack(t.id)}
            onLike={() => toggleLike(t.id)}
            isLiked={likedIds.has(t.id)}
          />
        ))}
      </div>
    </div>
  );
}
