import { useEffect, useRef } from 'react';
import { Play, Pause, SkipBack, SkipForward, Volume2 } from 'lucide-react';
import { useAudioStore } from '@/store/useAudioStore';
import { formatTime } from '@/utils/formatTime';

// 全英文 aria 和 placeholder，避免多余汉字
export default function PlayerBar() {
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const currentIndex = useAudioStore((s) => s.currentIndex);
  const tracks = useAudioStore((s) => s.tracks);
  const currentTrack = tracks[currentIndex];
  const isPlaying = useAudioStore((s) => s.isPlaying);
  const currentTime = useAudioStore((s) => s.currentTime);
  const duration = useAudioStore((s) => s.duration);
  const volume = useAudioStore((s) => s.volume);

  const togglePlay = useAudioStore((s) => s.toggle);
  const nextTrack = useAudioStore((s) => s.next);
  const prevTrack = useAudioStore((s) => s.prev);
  const setTime = useAudioStore((s) => s.setTime);
  const setDuration = useAudioStore((s) => s.setDuration);
  const setVolume = useAudioStore((s) => s.setVolume);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (currentTrack) {
      if (audio.src !== currentTrack.audioUrl) {
        audio.src = currentTrack.audioUrl;
        audio.load();
      }
      if (isPlaying) {
        const p = audio.play();
        if (p && typeof p.catch === 'function') p.catch(() => {});
      } else {
        audio.pause();
      }
    } else {
      audio.pause();
    }
  }, [currentIndex, currentTrack?.audioUrl, isPlaying]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.volume = volume;
  }, [volume]);

  const onSeek = (val: number) => {
    const audio = audioRef.current;
    setTime(val);
    if (audio && isFinite(audio.duration)) {
      audio.currentTime = val;
    }
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 z-40 bg-black text-white px-6 py-4 w-full">
      <audio
        ref={audioRef}
        onTimeUpdate={(e) => setTime(e.currentTarget.currentTime)}
        onDurationChange={(e) => setDuration(e.currentTarget.duration || 0)}
        onLoadedMetadata={(e) => setDuration(e.currentTarget.duration || 0)}
        onEnded={() => nextTrack()}
        preload="metadata"
      />

      <div className="flex items-center gap-5 md:gap-8 max-w-site mx-auto">
        <div className="flex items-center gap-4 min-w-0 w-[200px] md:w-[260px]">
          <div
            className={
              'w-14 h-14 md:w-16 md:h-16 rounded-[2px] object-cover bg-ink-800 overflow-hidden flex-shrink-0 relative ' +
              (currentTrack && isPlaying ? 'animate-spin-slow' : '')
            }
            style={{
              backgroundImage: currentTrack ? `url(${currentTrack.coverUrl})` : undefined,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
            }}
          />
          <div className="min-w-0 hidden sm:block">
            <div className="font-display text-lg truncate">
              {currentTrack?.title ?? '—'}
            </div>
            <div className="text-sm text-white/60 truncate">
              {currentTrack?.artist ?? '—'}
            </div>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 max-w-2xl mx-auto w-full">
          <div className="flex justify-center items-center gap-5">
            <button onClick={prevTrack} className="text-white/80 hover:text-white transition-colors p-1" aria-label="Previous">
              <SkipBack className="w-[18px] h-[18px]" strokeWidth={2} />
            </button>
            <button
              onClick={togglePlay}
              className="w-11 h-11 rounded-full border-2 border-white/90 flex items-center justify-center hover:bg-white/10 transition-colors"
              aria-label={isPlaying ? 'Pause' : 'Play'}
            >
              {isPlaying
                ? <Pause className="w-5 h-5" strokeWidth={2.25} />
                : <Play className="w-5 h-5 translate-x-[1px]" strokeWidth={2.25} />}
            </button>
            <button onClick={nextTrack} className="text-white/80 hover:text-white transition-colors p-1" aria-label="Next">
              <SkipForward className="w-[18px] h-[18px]" strokeWidth={2} />
            </button>
          </div>

          <div className="flex items-center justify-center w-full">
            <span className="text-xs text-white/60 tabular-nums w-10 text-right">{formatTime(currentTime)}</span>
            <input
              type="range"
              min={0}
              max={duration || 0}
              value={currentTime}
              onChange={(e) => onSeek(Number(e.target.value))}
              className="slider flex-1 mx-3"
              style={{ ['--progress' as any]: `${duration ? (currentTime / duration) * 100 : 0}%` } as React.CSSProperties}
            />
            <span className="text-xs text-white/60 tabular-nums w-10">{formatTime(duration)}</span>
          </div>
        </div>

        <div className="hidden md:flex items-center gap-3 w-48 flex-shrink-0">
          <Volume2 className="w-[18px] h-[18px] text-white/80" strokeWidth={2} />
          <input
            type="range"
            min={0}
            max={1}
            step={0.01}
            value={volume}
            onChange={(e) => setVolume(Number(e.target.value))}
            className="slider flex-1"
            style={{ ['--progress' as any]: `${volume * 100}%` } as React.CSSProperties}
          />
        </div>
      </div>
    </div>
  );
}
