export interface Track {
  id: string;
  title: string;
  artist: string;
  album: string;
  durationSec: number;
  coverUrl: string;
  audioUrl: string;
}

/* ============================================================
 * 仅保留用户上传的唯一一首本地音频 fog-over-hills.mp3
 *   - 音频文件: public/audio/fog-over-hills.mp3 （用户确认仅此一首）
 *   - 封面: 本地 SVG 黑白极简风格（不请求外网图片）
 *   - 其余示例曲目已删除，保持"一首"配置，其他页面/组件代码 0 改动
 * ========================================================== */
function buildCover(bg: string, label: string): string {
  const svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 600 600">
  <defs>
    <linearGradient id="g" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0%"  stop-color="${bg}"/>
      <stop offset="100%" stop-color="#000000"/>
    </linearGradient>
  </defs>
  <rect width="600" height="600" fill="url(#g)"/>
  <circle cx="300" cy="300" r="140" fill="none" stroke="#ffffff55" stroke-width="2"/>
  <circle cx="300" cy="300" r="22"  fill="#ffffffaa"/>
  <text x="50%" y="520" font-family="'Playfair Display','Noto Serif SC',serif" font-size="38" fill="#ffffffcc" text-anchor="middle">
    ${label}
  </text>
</svg>`
  return 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(svg)
}

const LOCAL_AUDIO = '/audio/fog-over-hills.mp3'

// === 仅此一首（用户仅提供 fog-over-hills 音频文件） ===
const tracks: Track[] = [
  {
    id: 't1',
    title: 'Fog Over Hills',
    artist: 'Song Yan',
    album: 'Monochrome Works',
    durationSec: 214,
    coverUrl: buildCover('#1a1a1a', 'FOG  OVER  HILLS'),
    audioUrl: LOCAL_AUDIO,
  },
]

export default tracks
