import { useEffect, useRef, useCallback } from 'react'
import { X } from 'lucide-react'
import type { VideoItem } from '@/data/videos'

interface VideoModalProps {
  open: boolean
  item: VideoItem | null
  onClose: () => void
}

export default function VideoModal({ open, item, onClose }: VideoModalProps) {
  const videoRef = useRef<HTMLVideoElement>(null)

  const handleKeyDown = useCallback(
    (e: KeyboardEvent) => {
      if (!open) return
      if (e.key === 'Escape') onClose()
    },
    [open, onClose]
  )

  useEffect(() => {
    if (open) {
      document.body.style.overflow = 'hidden'
      if (videoRef.current) {
        videoRef.current.play().catch(() => {})
      }
    } else {
      document.body.style.overflow = ''
      if (videoRef.current) {
        videoRef.current.pause()
        videoRef.current.currentTime = 0
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => {
      document.body.style.overflow = ''
      window.removeEventListener('keydown', handleKeyDown)
    }
  }, [open, handleKeyDown])

  if (!open || !item) return null

  return (
    <div className="fixed inset-0 z-50 bg-black/90 lightbox-backdrop animate-fade-in flex items-center justify-center p-4 sm:p-6 lg:p-10">
      <div className="w-full max-w-5xl bg-ink-950 border border-ink-800 rounded-[1px] overflow-hidden shadow-float">
        <div className="flex items-center justify-between px-5 sm:px-6 py-4 border-b border-ink-800">
          <div>
            <h3 className="font-display text-xl sm:text-2xl text-white">{item.title}</h3>
            <p className="text-xs text-white/40 tracking-wider mt-1 uppercase">{item.year} · {item.duration}</p>
          </div>
          <button
            onClick={onClose}
            className="w-10 h-10 rounded-full border border-white/30 text-white/70 flex items-center justify-center transition-colors hover:bg-white hover:text-black hover:border-white shrink-0"
            aria-label="关闭"
          >
            <X size={20} strokeWidth={1.5} />
          </button>
        </div>

        <div className="aspect-video bg-black">
          <video
            ref={videoRef}
            className="w-full h-full"
            controls
            preload="metadata"
            src={item.videoUrl}
          />
        </div>

        <div className="px-5 sm:px-6 py-4 border-t border-ink-800">
          <p className="text-sm text-white/60 leading-relaxed">{item.description}</p>
        </div>
      </div>
    </div>
  )
}
