import ContactCards from '@/components/contact/ContactCards';
import SocialLinks from '@/components/contact/SocialLinks';
import ContactForm from '@/components/contact/ContactForm';

export default function Contact() {
  return (
    <div>
      {/* 极简 Hero：纯英文，去掉中文标题 */}
      <section className="relative h-[28vh] md:h-[34vh] bg-[#0e0e0e] overflow-hidden">
        <div className="absolute inset-0 bg-black/70" />
        <div className="relative h-full flex flex-col items-center justify-center text-white text-center px-4">
          <p className="uppercase tracking-[0.4em] text-xs text-white/70 mb-4">
            Reach · 04
          </p>
          <h1 className="font-display text-5xl md:text-7xl tracking-wider animate-fade-in-up">
            CONTACT
          </h1>
        </div>
      </section>

      <main className="container max-w-site py-20">
        <ContactCards />
        <SocialLinks />
        <ContactForm />
      </main>
    </div>
  );
}
