import { socials } from '@/data/social';

// 标题：英文，避免多余汉字
export default function SocialLinks() {
  return (
    <section className="mt-20 mx-auto max-w-3xl text-center">
      <h3 className="font-display text-3xl">Find Me Online</h3>
      <div className="h-px bg-ink-900/10 w-20 mx-auto mt-6" />

      <div className="grid xs:grid-cols-3 md:grid-cols-6 gap-4 mt-10">
        {socials.map((s) => {
          const Icon = s.icon;
          return (
            <a
              key={s.name}
              href={s.url}
              target="_blank"
              rel="noreferrer noopener"
              className="aspect-square flex flex-col items-center justify-center border hairline group hover:bg-black hover:text-white transition-colors duration-500"
            >
              <Icon className="w-6 h-6" strokeWidth={1.8} />
              <div className="text-xs mt-2 text-ink-500 group-hover:text-white/80 transition-colors">
                {s.name}
              </div>
            </a>
          );
        })}
      </div>
    </section>
  );
}
