import { Instagram, Twitter, Youtube, Github, Dribbble, Mail } from 'lucide-react';

// 极简：全英文，去掉多余汉字；保留 Sitemap 但链接用英文；去掉中文简介
export default function Footer() {
  const year = new Date().getFullYear();
  return (
    <footer className="border-t hairline bg-white mt-0">
      <div className="container max-w-site py-12">
        <div className="grid md:grid-cols-3 gap-10">
          {/* Brand */}
          <div>
            <div className="flex items-center gap-3">
              <span className="w-9 h-9 border border-black flex items-center justify-center font-display text-sm tracking-tight">
                SY
              </span>
              <span className="font-display text-2xl tracking-[0.2em] uppercase">Song Yan</span>
            </div>
            <p className="text-sm text-ink-500 mt-5 leading-relaxed max-w-xs">
              Visual artist — monochrome works, moving images &amp; sound.
            </p>
          </div>

          {/* Sitemap */}
          <div>
            <div className="uppercase tracking-[0.25em] text-xs text-ink-500 mb-5">
              Sitemap
            </div>
            <ul className="space-y-2 text-sm text-ink-700 uppercase tracking-wider">
              <li><a href="/" className="link-underline">Home</a></li>
              <li><a href="/images" className="link-underline">Images</a></li>
              <li><a href="/videos" className="link-underline">Videos</a></li>
              <li><a href="/audio" className="link-underline">Audio</a></li>
              <li><a href="/contact" className="link-underline">Contact</a></li>
            </ul>
          </div>

          {/* Elsewhere */}
          <div>
            <div className="uppercase tracking-[0.25em] text-xs text-ink-500 mb-5">
              Elsewhere
            </div>
            <div className="flex items-center gap-3 flex-wrap">
              {[
                { I: Instagram, href: '#', l: 'Instagram' },
                { I: Twitter,   href: '#', l: 'Twitter' },
                { I: Youtube,   href: '#', l: 'YouTube' },
                { I: Github,    href: '#', l: 'GitHub' },
                { I: Dribbble,  href: '#', l: 'Dribbble' },
                { I: Mail,      href: 'mailto:hello@songyan.art', l: 'Email' },
              ].map((s) => (
                <a
                  key={s.l}
                  href={s.href}
                  target="_blank"
                  rel="noreferrer noopener"
                  aria-label={s.l}
                  className="w-10 h-10 border hairline flex items-center justify-center text-ink-700 hover:bg-black hover:text-white transition-colors duration-300"
                >
                  <s.I className="w-4 h-4" strokeWidth={1.8} />
                </a>
              ))}
            </div>
            <p className="text-sm text-ink-500 mt-6">hello@songyan.art</p>
          </div>
        </div>

        <div className="mt-12 pt-6 border-t hairline flex flex-col md:flex-row items-center justify-between gap-4 text-xs text-ink-500 tracking-wider">
          <div>&copy; {year} Song Yan. All rights reserved.</div>
          <div className="uppercase tracking-[0.25em]">
            Designed &amp; Crafted by Song Yan Studio
          </div>
        </div>
      </div>
    </footer>
  );
}
