import { Play, Pause, Heart } from 'lucide-react';
// 注意：项目里音频数据在 @/data/audios，不是 @/data/tracks（之前的路径是错的）
import type { Track } from '@/data/audios';
import { formatTime } from '@/lib/utils';
import { cn } from '@/lib/utils';

interface TrackItemProps {
  track: Track;
  index: number;
  isActive: boolean;
  isPlaying: boolean;
  onPlay: () => void;
  onLike: () => void;
  isLiked: boolean;
}

// aria-label 全部英文，避免多余汉字
export default function TrackItem({
  track,
  index,
  isActive,
  isPlaying,
  onPlay,
  onLike,
  isLiked,
}: TrackItemProps) {
  return (
    <div
      onClick={onPlay}
      className={cn(
        'flex items-center gap-4 px-5 py-4 border-b hairline group hover:bg-ink-50 transition-colors cursor-pointer',
        isActive && 'bg-ink-50 border-l-2 border-black pl-4',
      )}
    >
      <div className="w-8 text-center text-ink-500 relative flex items-center justify-center h-5">
        <span className={cn(isActive && 'opacity-0')}>{index + 1}</span>
        {isActive && (
          <div className="absolute inset-0 flex items-center justify-center">
            {isPlaying
              ? <Pause className="w-4 h-4 text-black" strokeWidth={2.25} />
              : <Play className="w-4 h-4 text-black" strokeWidth={2.25} />}
          </div>
        )}
      </div>

      <div className="flex-1 min-w-0">
        <div
          className={cn(
            'text-lg font-display truncate',
            isActive ? 'text-black font-semibold' : 'text-ink-900',
          )}
        >
          {track.title}
        </div>
        <div className="text-sm text-ink-500 truncate">
          {track.artist} &middot; {track.album}
        </div>
      </div>

      <div className="w-20 text-right text-sm text-ink-500 tabular-nums">
        {formatTime(track.durationSec)}
      </div>

      <button
        onClick={(e) => { e.stopPropagation(); onLike(); }}
        className="flex items-center justify-center w-9 h-9 rounded-full text-ink-500 hover:text-black transition-colors"
        aria-label={isLiked ? 'Unlike' : 'Like'}
      >
        <Heart
          className={cn('w-5 h-5 transition-all', isLiked ? 'fill-black text-black' : 'stroke-current')}
          strokeWidth={1.8}
        />
      </button>
    </div>
  );
}
