import Playlist from '@/components/audio/Playlist';
import tracks from '@/data/audios';

export default function Audio() {
  const count = String(tracks.length).padStart(2, '0');
  return (
    <div className="pb-36">
      {/* 极简 Hero：纯英文，去掉中文标题和描述 */}
      <section className="relative h-[32vh] md:h-[38vh] bg-[#0e0e0e] overflow-hidden">
        <div className="absolute inset-0 bg-black/60" />
        <div className="relative h-full flex flex-col items-center justify-center text-white text-center px-4">
          <p className="uppercase tracking-[0.4em] text-xs text-white/70 mb-4">
            Sounds · {count}
          </p>
          <h1 className="font-display text-5xl md:text-7xl tracking-wider animate-fade-in-up">
            AUDIO
          </h1>
        </div>
      </section>

      <main className="container max-w-site py-16">
        <Playlist />
      </main>
    </div>
  );
}
