import { create } from "zustand";
import initialTracks, { Track } from "../data/audios";

export const getCurrentTrack = (state: AudioState): Track | undefined => {
  return state.tracks[state.currentIndex];
};

interface AudioState {
  tracks: Track[];
  currentIndex: number;
  currentTrackId: string | null;
  isPlaying: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  likedIds: Set<string>;

  toggle: () => void;
  togglePlay: () => void;
  play: () => void;
  pause: () => void;
  next: () => void;
  nextTrack: () => void;
  prev: () => void;
  prevTrack: () => void;
  setTrack: (i: number) => void;
  playTrack: (id: string) => void;
  setTime: (t: number) => void;
  setDuration: (d: number) => void;
  setVolume: (v: number) => void;
  toggleLike: (id: string) => void;
}

const firstId = initialTracks[0]?.id ?? null;

export const useAudioStore = create<AudioState>((set, get) => ({
  tracks: initialTracks,
  currentIndex: 0,
  currentTrackId: firstId,
  isPlaying: false,
  currentTime: 0,
  duration: 0,
  volume: 0.7,
  likedIds: new Set(),

  toggle: () =>
    set((state) => ({
      isPlaying: !state.isPlaying,
    })),

  togglePlay: () =>
    set((state) => ({
      isPlaying: !state.isPlaying,
    })),

  play: () => set({ isPlaying: true }),

  pause: () => set({ isPlaying: false }),

  next: () => {
    const { tracks, currentIndex } = get();
    const nextIndex = currentIndex + 1 >= tracks.length ? 0 : currentIndex + 1;
    set({
      currentIndex: nextIndex,
      currentTrackId: tracks[nextIndex]?.id ?? null,
      currentTime: 0,
      duration: 0,
    });
  },

  nextTrack: () => {
    get().next();
  },

  prev: () => {
    const { tracks, currentIndex } = get();
    const prevIndex =
      currentIndex - 1 < 0 ? tracks.length - 1 : currentIndex - 1;
    set({
      currentIndex: prevIndex,
      currentTrackId: tracks[prevIndex]?.id ?? null,
      currentTime: 0,
      duration: 0,
    });
  },

  prevTrack: () => {
    get().prev();
  },

  setTrack: (i: number) => {
    const { tracks } = get();
    set({
      currentIndex: i,
      currentTrackId: tracks[i]?.id ?? null,
      currentTime: 0,
      duration: 0,
    });
  },

  playTrack: (id: string) => {
    const { tracks } = get();
    const idx = tracks.findIndex((t) => t.id === id);
    if (idx >= 0) {
      get().setTrack(idx);
      set({ isPlaying: true });
    }
  },

  setTime: (t: number) => set({ currentTime: t }),

  setDuration: (d: number) => set({ duration: d }),

  setVolume: (v: number) => set({ volume: v }),

  toggleLike: (id: string) =>
    set((state) => {
      const next = new Set(state.likedIds);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return { likedIds: next };
    }),
}));
