import { useMemo } from 'react'

/* ==========================================================================
 * 图片板块 & 子分类顺序 & 中英标题（严格按用户给定顺序，不做任何变动）
 *   第一块：story-illust  故事系列插画  →  robot → monster → knight → dream → bewitch-woman
 *   第二块：animal-illust 动物系列       →  animal
 *   第三块：install-art   装置系列       →  install
 *   第四块：fine-art      综合艺术作品    →  art-works → ceramics
 *
 * 注：folder 字段使用磁盘实际目录名（处理了大小写、空格、连字符差异）
 * ========================================================================*/
interface SubSectionDef {
  folder: string       // 实际磁盘子目录名
  titleZh: string      // 中文标题
  titleEn: string      // 英文标题
}
interface SectionDef {
  folder: string       // 实际磁盘板块目录名
  titleZh: string      // 板块中文标题
  titleEn: string      // 板块英文标题
  subs: SubSectionDef[]
}

const SECTIONS: SectionDef[] = [
  {
    folder: 'story-illust',
    titleZh: '故事系列插画',
    titleEn: 'Story Illustration',
    subs: [
      /* ===== 仅替换故事板块的 5 个子分类（folder 严格用磁盘实际大小写：monster-Town / my-Dream-Grandma） ===== */
      { folder: 'zero-era',                       titleZh: '零纪元',        titleEn: 'Zero Era'                        },
      { folder: 'monster-Town',                    titleZh: '怪物小镇',      titleEn: 'Monster Town'                     },
      { folder: 'the-adventure-of-a-knight',       titleZh: '骑士冒险录',    titleEn: 'The Adventure of a Knight'        },
      { folder: 'my-Dream-Grandma',                titleZh: '祖母之梦',      titleEn: 'My Dream Grandma'                 },
      { folder: 'the-accident-of-the-little-witch',titleZh: '小女巫奇遇记',  titleEn: 'The Accident of the Little Witch' },
    ],
  },
  /* ==========================================================
   *  以下 animal-illust / install-art / fine-art 三个板块
   *  严格保留原有代码字节，一字不动（用户要求完全不变）
   * ========================================================*/
  {
    folder: 'animal-illust',
    titleZh: '动物系列',
    titleEn: 'Animal Illustration',
    subs: [
      { folder: 'animal',            titleZh: '动物系列',    titleEn: 'Animal'            },
    ],
  },
  {
    folder: 'install-art',
    titleZh: '装置系列',
    titleEn: 'Installation Art',
    subs: [
      { folder: 'install',           titleZh: '装置系列',    titleEn: 'Installation'      },
    ],
  },
  {
    folder: 'fine-art',
    titleZh: '综合艺术作品',
    titleEn: 'Fine Art',
    subs: [
      // 用户写的 "art-works" 磁盘上是 "art works"（空格），按实际路径写
      { folder: 'art works',         titleZh: '艺术作品',    titleEn: 'Art Works'         },
      { folder: 'ceramics',          titleZh: '陶艺系列',    titleEn: 'Ceramics'          },
    ],
  },
]

/* ==========================================================================
 * Vite import.meta.glob：一次性动态读取 src/assets 下所有板块的图片
 *   - eager:true  同步打包（不生成 dynamic-import chunk）
 *   - as:'url'    返回打包后可直接用作 <img src> 的 URL 字符串
 *   - 覆盖 jpg/jpeg/png/webp 四种常见扩展名
 *
 * 说明：这是 Vite 原生提供的能力（与框架无关，Vue / React 下都可用）。
 *      图片路径全部交由 Vite 哈希+打包，避免手写 /src/assets/xxx 字符串导致
 *      生产构建 404 的问题（对应经验 270265 的 FailureExperience 规避方案）。
 * ========================================================================*/
const imageModules = import.meta.glob(
  '/src/assets/**/*.{jpg,jpeg,png,webp}',
  { eager: true, as: 'url' }
) as Record<string, string>

/** 从文件路径中抽取"文件名末尾数字序号"：art works-16.png → 16, illust-Bewitching woman-14.jpg → 14 */
function extractOrder(filePath: string): number {
  const base = filePath.split('/').pop() ?? ''
  const m = base.match(/(\d+)(?:\.[^.]+)$/)
  return m ? Number.parseInt(m[1], 10) : Number.MAX_SAFE_INTEGER
}

export default function Images() {
  /* ========================================================================
   * 把 glob 的扁平结果按 SECTION.subs 的固定顺序 & 文件名末尾数字升序 重排
   * ======================================================================*/
  const layout = useMemo(() => {
    // 先把 glob 结果转为 [{ filePath, url }] 列表，方便过滤
    const allFiles = Object.entries(imageModules).map(([path, url]) => ({ path, url }))

    return SECTIONS.map((sec) => {
      const sectionPrefix = `/src/assets/${sec.folder}/`
      return {
        ...sec,
        subs: sec.subs.map((sub) => {
          const subPrefix = `${sectionPrefix}${sub.folder}/`
          const matches = allFiles.filter((f) => f.path.startsWith(subPrefix))
          // 严格按文件名末尾 01、02、03 数字从小到大排序
          matches.sort((a, b) => extractOrder(a.path) - extractOrder(b.path))
          return {
            ...sub,
            count: matches.length,
            urls: matches.map((m) => m.url),
          }
        }),
      }
    })
  }, [])

  return (
    <div className="min-h-screen bg-white text-ink-950">
      {/* ===== 顶部 Hero（保留极简黑白风格，纯英文标题，与整站一致） ===== */}
      <section className="h-[32vh] md:h-[38vh] relative bg-[#0e0e0e] overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-b from-black/10 via-black/40 to-black/80" />
        <div className="relative z-10 h-full flex flex-col items-center justify-center text-white text-center px-4">
          <p className="uppercase tracking-[0.4em] text-xs text-white/60 animate-fade-in-up">
            Works · 01
          </p>
          <h1
            className="font-display text-5xl md:text-7xl mt-4 animate-fade-in-up"
            style={{ animationDelay: '100ms' }}
          >
            IMAGES
          </h1>
        </div>
      </section>

      {/* ===== 四大板块（严格按顺序渲染） ===== */}
      <main className="container max-w-site py-16 px-4 sm:px-6">
        {layout.map((sec, sIdx) => (
          <section
            key={sec.folder}
            className={`mb-20 ${sIdx === layout.length - 1 ? 'mb-10' : ''}`}
          >
            {/* 板块一级标题：中文 + 英文 */}
            <div className="mb-10 border-l-4 border-ink-950 pl-5 py-1">
              <h2 className="font-display text-2xl md:text-3xl tracking-wide text-ink-950">
                <span className="mr-3">{sec.titleZh}</span>
                <span className="text-sm md:text-base font-sans uppercase tracking-[0.22em] text-ink-400 align-middle">
                  {sec.titleEn}
                </span>
              </h2>
            </div>

            {/* 子分类：每个二级分类带中英标题 + grid 图片 + hover 轻微放大 */}
            {sec.subs.map((sub) => (
              <div key={`${sec.folder}__${sub.folder}`} className="mb-14 last:mb-0">
                {/* 子分类二级标题 */}
                <div className="mb-5 flex items-baseline gap-3">
                  <h3 className="font-display text-xl md:text-2xl text-ink-900">
                    {sub.titleZh}
                  </h3>
                  <span className="h-px w-8 bg-ink-300" aria-hidden="true" />
                  <span className="text-sm uppercase tracking-[0.2em] text-ink-400">
                    {sub.titleEn}
                  </span>
                  <span className="ml-auto text-xs text-ink-300 tabular-nums">
                    {String(sub.count).padStart(2, '0')} items
                  </span>
                </div>

                {sub.urls.length === 0 ? (
                  <p className="text-sm text-ink-300 py-8 italic">
                    No images in this category.
                  </p>
                ) : (
                  <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 sm:gap-5 lg:gap-6">
                    {sub.urls.map((url, i) => (
                      <figure
                        key={url}
                        className="group relative aspect-square overflow-hidden rounded-xl bg-ink-50 ring-1 ring-ink-100"
                      >
                        {/* 轻微放大：默认 scale(1) → hover: scale(1.04)，transition 0.5s */}
                        <img
                          src={url}
                          alt={`${sub.titleEn} No.${String(i + 1).padStart(2, '0')}`}
                          loading="lazy"
                          decoding="async"
                          className="w-full h-full object-cover transition-transform duration-500 ease-out will-change-transform
                                     group-hover:scale-[1.04] group-hover:-translate-y-[1px]"
                        />
                        {/* hover 时的极细遮罩（可选，不影响放大效果） */}
                        <figcaption
                          aria-hidden="true"
                          className="pointer-events-none absolute inset-0 bg-black/0 transition-colors duration-500
                                     group-hover:bg-black/[0.04]"
                        />
                      </figure>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </section>
        ))}
      </main>
    </div>
  )
}
