import type { VideoItem } from '@/data/videos'

interface VideoCardProps {
  item: VideoItem
  onClick: () => void // 点击标题区打开 Modal（大屏播放），视频原生控件区不触发
}

export default function VideoCard({ item, onClick }: VideoCardProps) {
  return (
    <div className="group border hairline overflow-hidden bg-white">
      {/* 视频区：嵌入 B站 iframe 播放器
          - onClick.stopPropagation()：点击控件/视频不冒泡到标题区，避免误弹 Modal */}
      <div
        className="aspect-video relative overflow-hidden"
        onClick={(e) => e.stopPropagation()}
      >
        <iframe
          src={item.bilibiliUrl}
          style={{ width: "100%", aspectRatio: "16/9", border: "none" }}
          allowFullScreen
        ></iframe>
        <div className="absolute top-3 right-3 bg-black/80 text-white text-xs px-2 py-1 tracking-wide pointer-events-none">
          {item.duration}
        </div>
      </div>

      {/* 标题/描述区：点击仍可打开 VideoModal 大屏弹窗（保持原有交互可选） */}
      <div className="p-5 cursor-pointer" onClick={onClick}>
        <div className="flex items-start justify-between gap-4">
          <h3 className="font-display text-2xl text-ink-950 leading-tight">{item.title}</h3>
          <span className="text-xs text-ink-400 uppercase tracking-wider shrink-0 pt-1.5">{item.year}</span>
        </div>
        <p className="mt-3 text-sm text-ink-500 line-clamp-2">{item.description}</p>
      </div>
    </div>
  )
}
