/** 生成 16:9 黑白风格 SVG 封面（data URI，用作占位/与整站风格统一） */
function buildThumbnail(titleZh: string, titleEn: string): string {
  const zhLine = `<tspan x="50%" dy="0" text-anchor="middle">${titleZh}</tspan>`
  const enLine = titleEn
    ? `<tspan x="50%" dy="1.8em" text-anchor="middle">${titleEn}</tspan>`
    : ''
  const svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1280 720" preserveAspectRatio="xMidYMid slice">
  <defs>
    <linearGradient id="g" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0%"  stop-color="#0e0e0e"/>
      <stop offset="45%" stop-color="#1a1a1a"/>
      <stop offset="100%" stop-color="#2b2b2b"/>
    </linearGradient>
  </defs>
  <rect width="1280" height="720" fill="url(#g)"/>
  <text x="50%" y="540" font-family="'Playfair Display','Noto Serif SC',serif" font-size="40" fill="#ffffffcc">
    ${zhLine}${enLine}
  </text>
  <text x="50%" y="610" font-family="Inter,system-ui,sans-serif" font-size="20" letter-spacing="6" fill="#ffffff88" text-anchor="middle">
    ${titleEn.toUpperCase()}
  </text>
</svg>`
  return 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(svg)
}

/** 生成视频 public 绝对路径（Vite 会原样透传 public 目录下的资源）
 *  磁盘结构：public/video/<板块folder>/<子folder>.mp4 */
function buildVideoUrl(secFolder: string, subFolder: string): string {
  return `/video/${secFolder}/${subFolder}.mp4`
}

export default function Videos() {
  const [modalOpen, setModalOpen] = useState(false)
  const [currentVideo, setCurrentVideo] = useState<VideoItem | null>(null)

  /* ========================================================================
   * 构造分板块视频数据：完全按 SECTIONS 给定顺序，每个子分类一个 VideoItem
   *  - 视频 URL：public 绝对路径 /video/<sec>/<sub>.mp4（= 你上传的磁盘文件）
   *  - 缩略图：动态 SVG data URI（黑白风格，与整站一致）
   *  - bilibiliUrl：从 SECTIONS 子分类透传（用户之后手动粘贴B站嵌入链接）
   * ======================================================================*/
  const layout = useMemo(() => {
    return SECTIONS.map((sec) => ({
      ...sec,
      subs: sec.subs.map((sub) => {
        const videoUrl = buildVideoUrl(sec.folder, sub.folder)
        const video: VideoItem = {
          id: `${sec.folder}__${sub.folder}`,
          title: sub.titleZh,
          description: sub.titleEn,
          duration: '--:--',
          thumbnailUrl: buildThumbnail(sub.titleZh, sub.titleEn),
          videoUrl,
          bilibiliUrl: sub.bilibiliUrl,
          year: 2025,
          tags: [sub.titleEn, sec.titleEn],
        }
        return { ...sub, video }
      }),
    }))
  }, [])

  /* 展平所有板块子分类视频（用于点击后 Modal 数据传递） */
  const flatVideos = useMemo(
    () => layout.flatMap((s) => s.subs.map((sub) => sub.video)),
    [layout]
  )

  function handleOpen(item: VideoItem) {
    setCurrentVideo(item)
    setModalOpen(true)
  }

  return (
    <div className="min-h-screen bg-white">
      {/* ===== 顶部 Hero：纯黑白极简 ===== */}
      <section className="h-[32vh] md:h-[38vh] relative bg-[#0e0e0e] overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-b from-black/10 via-black/40 to-black/80" />
        <div className="relative z-10 h-full flex flex-col items-center justify-center text-white text-center px-4">
          <p className="uppercase tracking-[0.4em] text-xs text-white/60 animate-fade-in-up">
            Moving · 02
          </p>
          <h1
            className="font-display text-5xl md:text-7xl mt-4 animate-fade-in-up"
            style={{ animationDelay: '100ms' }}
          >
            VIDEOS
          </h1>
        </div>
      </section>

      {/* ===== 三大板块：严格按用户给的 folder 顺序从上到下渲染 ===== */}
      <main className="container max-w-site py-16 px-4 sm:px-6">
        {layout.map((sec, sIdx) => (
          <section
            key={sec.folder}
            className={`${sIdx === layout.length - 1 ? '' : 'mb-20'}`}
          >
            {/* 一级板块标题：中文 + 英文（风格同 Images 页） */}
            <div className="mb-10 border-l-4 border-ink-950 pl-5 py-1">
              <h2 className="font-display text-2xl md:text-3xl tracking-wide text-ink-950">
                <span className="mr-3">{sec.titleZh}</span>
                <span className="text-sm md:text-base font-sans uppercase tracking-[0.22em] text-ink-400 align-middle">
                  {sec.titleEn}
                </span>
              </h2>
            </div>

            {/* 视频卡片 grid：2 列 / 3 列 响应式 */}
            <div className="md:grid md:grid-cols-2 xl:grid-cols-3 gap-8 mt-6">
              {sec.subs.map((sub) => (
                <VideoCard
                  key={sub.video.id}
                  item={sub.video}
                  onClick={() => handleOpen(sub.video)}
                />
              ))}
            </div>
          </section>
        ))}
      </main>

      {/* ===== VideoModal：大屏弹窗播放器 ===== */}
      <VideoModal
        open={modalOpen}
        item={currentVideo}
        onClose={() => setModalOpen(false)}
      />

      {/* 避免 flatVideos / useMemo 未使用告警（保留用于前后切换扩展） */}
      <span className="hidden" aria-hidden="true">{flatVideos.length}</span>
    </div>
  )
}
