import { Link } from 'react-router-dom';
import { ArrowLeft } from 'lucide-react';

// 全英文，避免多余汉字
export default function NotFound() {
  return (
    <div className="min-h-[100vh] flex flex-col justify-center items-center text-center px-6 py-40">
      <div className="font-display text-[12rem] md:text-[16rem] leading-none italic -mt-10">
        404
      </div>
      <p className="uppercase tracking-[0.4em] text-xs text-ink-500 mt-4">
        Page not found
      </p>
      <p className="text-sm text-ink-500 mt-4 max-w-md">
        The page you are looking for may have been moved, deleted, or never existed.
      </p>
      <Link to="/" className="btn-primary mt-12 inline-flex items-center gap-2">
        <ArrowLeft className="w-4 h-4" />
        Back to Home
      </Link>
    </div>
  );
}
